// Crimson Pro (Regular) — SIL Open Font License 1.1 (see CrimsonPro-OFL.txt).
// Embedded as base64 so the showcase font loads with zero bundler/base-path
// config (Storybook deploys under a GitHub Pages subpath). ~139 KB.
/* eslint-disable */
const BASE64 =
  '';

/** Decode the embedded Crimson Pro font to an ArrayBuffer. */
export function crimsonProFont(): ArrayBuffer {
  const bin = atob(BASE64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}
